<?phpnamespace App\Http\Controllers\Property;use App\Http\Controllers\BaseController;use App\Models\Property;use App\Core\Database;class PropertyController extends BaseController{    public function __construct()    {        parent::__construct();    }    /**     * Display a listing of properties.     */    public function index()    {        $this->data['page_title'] = 'Properties - ' . APP_NAME;        $this->data['breadcrumbs'] = [            ['title' => 'Home', 'url' => BASE_URL],            ['title' => 'Properties', 'url' => BASE_URL . 'properties']        ];        // Filters        $filters = [            'type' => $_GET['type'] ?? null,            'location' => $_GET['location'] ?? null,            'bedrooms' => $_GET['bedrooms'] ?? null,            'featured' => $_GET['featured'] ?? null,            'sort' => $_GET['sort'] ?? 'newest'        ];        // Budget parsing        if (!empty($_GET['budget'])) {            $budget = explode('-', $_GET['budget']);            if (count($budget) == 2) {                $filters['min_price'] = $budget[0];                $filters['max_price'] = $budget[1];            } elseif (strpos($_GET['budget'], '+') !== false) {                $filters['min_price'] = (int)str_replace('+', '', $_GET['budget']);            }        }        $propertyModel = new Property();        $properties = $propertyModel->searchProperties($filters, 20);        // Convert array of objects to array of arrays if needed, or view handles objects?        // View uses $property['id'], so it expects arrays.        // searchProperties returns array of Property objects (new static($result)).        // Property model extends Model. Model usually allows array access if it implements ArrayAccess or we treat it as object.        // Let's check Model.php.        // If Model doesn't implement ArrayAccess, accessing as array will fail.        // The view code uses $property['id'].        // I should convert objects to arrays or ensure Model supports array access.        // Or I can just pass the raw results from searchProperties if I modify it to return arrays?        // Actually searchProperties returns `array_map(fn($result) => new static($result), $results)`.        // Let's check if I can just use the raw results.        // I'll modify searchProperties to return arrays? No, better to keep it returning models.        // I will convert models to arrays here for the view, or update the view to use object syntax.        // Updating view to object syntax is better practice, but updating view is part of next step.        // Let's assume I'll update view to use objects ($property->id) OR convert here.        // To be safe and compatible with existing view logic (which uses ['id']), I'll convert to array.        $this->data['properties'] = $properties;        $this->data['total_properties'] = count($properties);        // Get locations (Cities)        try {            $db = Database::getInstance();            $stmt = $db->query("SELECT city, COUNT(*) as count FROM properties GROUP BY city ORDER BY city");            $cities = $stmt->fetchAll(\PDO::FETCH_ASSOC);            $locations = [];            foreach ($cities as $city) {                $locations['Uttar Pradesh'][] = $city;            }            $this->data['locations'] = $locations;        } catch (\Exception $e) {            $this->data['locations'] = [];        }        // Add extra CSS        $this->data['extra_css'] = '            <link rel="stylesheet" href="' . BASE_URL . 'public/css/pages.css">            <link href="https://unpkg.com/aos@2.3.1/dist/aos.css" rel="stylesheet">            <link href="https://unpkg.com/swiper@10/swiper-bundle.min.css" rel="stylesheet">            <link href="https://cdn.jsdelivr.net/npm/nouislider@15.7.0/dist/nouislider.min.css" rel="stylesheet">        ';        // Add extra JS        $this->data['extra_js'] = '            <script src="https://unpkg.com/aos@2.3.1/dist/aos.js"></script>            <script src="https://unpkg.com/swiper@10/swiper-bundle.min.js"></script>            <script src="https://cdn.jsdelivr.net/npm/nouislider@15.7.0/dist/nouislider.min.js"></script>            <script>                document.addEventListener("DOMContentLoaded", function() {                    AOS.init({                        duration: 800,                        once: true                    });                });            </script>        ';        return $this->render('pages/properties');    }    /**     * Display the specified property.     *     * @param  int  $id     */    public function show($id)    {        $this->data['page_title'] = 'Property Details - ' . APP_NAME;        $this->data['property_id'] = $id;        return $this->render('property/show');    }    /**     * Search for properties.     */    public function search()    {        $this->data['page_title'] = 'Search Properties - ' . APP_NAME;        return $this->render('property/search');    }}